# scripts/drill_scorecard.py
import json, pathlib, datetime

PASS_CRITERIA = {
    'feature_flag_drill': {
        'traffic_zero_at': 60,    # seconds
        'flag_disabled_at': 30,
    },
    'full_service_rollback': {
        'image_reverted_at': 300,  # 5 minutes
        'pods_ready_at': 420,      # 7 minutes
    },
    'game_day': {
        'recovery_time_s': 420,    # 7-minute SLA
    },
}

def score_drill(drill_type: str, results: dict) -> dict:
    criteria = PASS_CRITERIA.get(drill_type, {})
    grades = {}
    for metric, threshold in criteria.items():
        actual = results.get(metric)
        if actual is None:
            grades[metric] = 'MISSING'
        elif actual <= threshold:
            grades[metric] = f'PASS ({actual:.1f}s <= {threshold}s)'
        else:
            grades[metric] = f'FAIL ({actual:.1f}s > {threshold}s)'
    overall = all('PASS' in g for g in grades.values())
    return {'drill_type': drill_type, 'grades': grades, 'overall': 'PASS' if overall else 'FAIL',
            'timestamp': datetime.datetime.utcnow().isoformat()}

def save_scorecard(scorecard: dict, output_dir: str = 'logs/drills') -> pathlib.Path:
    pathlib.Path(output_dir).mkdir(parents=True, exist_ok=True)
    ts = scorecard['timestamp'].replace(':', '-')[:19]
    path = pathlib.Path(output_dir) / f"{scorecard['drill_type']}_{ts}.json"
    with open(path, 'w') as f:
        json.dump(scorecard, f, indent=2)
    return path
